 1	import React from 'react';
 2	
 3	import { WizardTab } from '@catalog/wizard/tabs';
 4	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 5	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 6	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 7	
 8	import WizardOverviewGrid from './components/WizardOverviewGrid';
 9	
10	import './WizardOverviewTab.scss';
11	
12	const WizardOverviewTab: WizardTab = ({ tabsData, updateVM, vm }) => (
13	  <PageSection className="wizard-overview-tab" variant={PageSectionVariants.light}>
14	    <SidebarEditor
15	      onResourceUpdate={(newVM) => updateVM(newVM)}
16	      pathsToHighlight={PATHS_TO_HIGHLIGHT.DETAILS_TAB}
17	      resource={vm}
18	    >
19	      {(resource) => <WizardOverviewGrid tabsData={tabsData} updateVM={updateVM} vm={resource} />}
20	    </SidebarEditor>
21	  </PageSection>
22	);
23	
24	export default WizardOverviewTab;

